const row = $input.first().json || {};

if (!row.usuario_id) {
  return [{
    json: {
      resultado: 'Não consegui salvar a preferência. Verifique se patient_phone, preference_key e preference_value foram enviados.',
      sucesso: false
    }
  }];
}

const preferencias = row.preferencias && typeof row.preferencias === 'object' ? row.preferencias : {};
const chave = row.preference_key || null;
const valor = row.preference_value || null;

return [{
  json: {
    resultado: `Preferência salva com sucesso para ${row.telefone}: ${chave} = ${valor}.`,
    sucesso: true,
    preferencia_salva: {
      telefone: row.telefone,
      chave,
      valor
    },
    preferencias,
    usuario_metadados: row.usuario_metadados || null
  }
}];
